function greet(name: string, prefix: string | null = null): string {
  if (prefix === null) {
    return "Hello, " + name;
  }
  return prefix + " " + name;
}

console.log(greet("Alice"));        // Hello, Alice
console.log(greet("Bob", "Dr."));   // Dr. Bob

