from dataclasses import dataclass

@dataclass
class Product:
    id: int
    name: str
    price: float
    in_stock: bool = True

    def discounted(self, pct: float) -> float:
        return self.price * (1 - pct / 100)

examples.toCode:
interface Product {
  id: number;
  name: string;
  price: number;
  inStock: boolean;
}

class ProductModel implements Product {
  inStock = true;
  constructor(
    public id: number,
    public name: string,
    public price: number,
  ) {}

  discounted(pct: number): number {
    return this.price * (1 - pct / 100);
  }
}
